class Solution {
    public int minimizedStringLength(String s) {
        int n = s.length();
        int[] lastIndex = new int[26];
        for (int i = 0; i < n; i++) {
            lastIndex[s.charAt(i) - 'a'] = i;
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            int left = lastIndex[c - 'a'];
            if (left != -1 && left < i) {
                sb.append(c);
            }
            lastIndex[c - 'a'] = i;
        }
        return sb.length();
    }
}
